export const QUESTIONS = [
  { level:"A1", sentence:"Je suis française mais j'habite ___ Canada depuis 14 ans.", options:["à","au","du","en"], correct:1, rule:"Devant un nom de pays masculin (le Canada), on utilise « au » (à + le). On dit « au Canada », « au Japon », « au Maroc ».", why:["« à » s'emploie devant les villes (à Paris), pas les pays masculins.",null,"« du » exprime la provenance (je viens du Canada), pas le lieu où l'on habite.","« en » s'emploie devant les pays féminins (en France) ou masculins commençant par une voyelle (en Iran)."] },
  { level:"A2", sentence:"Pratiquez votre français ___ nos collections d'exercices interactifs !", options:["avec","de","par","sur"], correct:0, rule:"« avec » indique le moyen/l'outil utilisé pour faire quelque chose. On pratique « avec » des exercices.", why:[null,"« de » n'exprime pas le moyen ici.","« par » indique plutôt l'agent ou le passage, pas l'outil.","« sur » indique une position ou un sujet, pas le moyen."] },
  { level:"B1", sentence:"Je n'ai pas encore téléphoné à Anne mais je ___ appellerai ce soir.", options:["l'","la","les","lui"], correct:0, rule:"« appeler quelqu'un » est un verbe transitif direct : le COD remplace « Anne » par « la », qui s'élide en « l' » devant une voyelle (l'appellerai).", why:[null,"« la » est correct sur le fond mais doit s'élider en « l' » devant le « a » de appellerai.","« les » est pluriel ; on parle d'une seule personne (Anne).","« lui » est un COI, employé avec « téléphoner à » mais pas avec « appeler » qui est direct."] },
  { level:"B1", sentence:"Il fait très chaud à l'intérieur et il est malheureusement ___ d'ouvrir la fenêtre.", options:["grave","sévère","dangereux","sérieux"], correct:2, rule:"« dangereux » exprime un risque/péril. Ouvrir la fenêtre présente un danger, d'où « il est dangereux de ».", why:["« grave » qualifie une situation sérieuse mais pas un risque physique d'action.","« sévère » se dit d'une personne stricte ou d'une punition.",null,"« sérieux » signifie important/réfléchi, pas risqué."] },
  { level:"B1", sentence:"Tu veux que je ___ les courses avant de rentrer ?", options:["fais","faisais","fasse","ferai"], correct:2, rule:"Après « vouloir que », on emploie le SUBJONCTIF. « fasse » est le subjonctif présent de faire.", why:["« fais » est l'indicatif présent ; interdit après vouloir que.","« faisais » est l'imparfait de l'indicatif.",null,"« ferai » est le futur de l'indicatif."] },
  { level:"B2", sentence:"La direction ne saurait être tenue pour ___ en cas de vol.", options:["auteur","cadre","garant","responsable"], correct:3, rule:"L'expression figée « être tenu pour responsable » signifie « être considéré comme responsable ». C'est une collocation fixe.", why:["« auteur » désigne celui qui fait l'acte, pas la responsabilité juridique dans cette tournure.","« cadre » est un poste ou un contexte.","« garant » se construit avec « se porter garant », pas « tenu pour garant » dans ce sens.",null] },
  { level:"B1", sentence:"___ David Mermet, son entraîneur, la championne a réussi avec brio ce pari fou de traverser l'Atlantique à la rame.", options:["À cause de","À travers","En raison de","Grâce à"], correct:3, rule:"« Grâce à » introduit une cause POSITIVE (un succès). Ici l'entraîneur a aidé à la réussite.", why:["« À cause de » introduit une cause NÉGATIVE (un problème).","« À travers » signifie en traversant, pas une cause.","« En raison de » est neutre/administratif, mais ne souligne pas l'aide bénéfique.",null] },
  { level:"B2", sentence:"L'âge de la pierre taillée ___ de 2 millions à 10 000 ans avant J.-C.", options:["dure","s'écoule","s'étend","survit"], correct:2, rule:"« s'étendre de... à... » exprime une période entre deux bornes temporelles. Idéal pour une époque historique.", why:["« dure » exprime une durée mais ne se construit pas avec « de... à... » de cette façon.","« s'écoule » se dit du temps qui passe, pas d'une période bornée.",null,"« survit » signifie continuer d'exister malgré tout."] },
  { level:"B2", sentence:"Notre émission vous propose de dresser le portrait ___ du nouveau chef du gouvernement.", options:["automate","machine","mécanique","robot"], correct:3, rule:"« robot » est ici le mot juste pour « portrait-robot » — une expression figée désignant un portrait reconstitué.", why:["« automate » désigne une machine autonome, pas ce type de portrait.","« machine » ne forme pas d'expression avec portrait.","« mécanique » est un adjectif/nom sans rapport ici.",null] },
  { level:"C1", sentence:"Quelle catastrophe ! En entendant la nouvelle j'ai été ___.", options:["enterré","harassé","ratissé","terrassé"], correct:3, rule:"« terrassé » signifie abattu, accablé par une émotion violente. Sens figuré adapté à une mauvaise nouvelle.", why:["« enterré » signifie mis en terre (littéral) ou oublié.","« harassé » signifie épuisé par la fatigue, pas par un choc émotionnel.","« ratissé » signifie fouillé/nettoyé, sans rapport.",null] },
  { level:"A1", sentence:"Antoine va ___ Liban pour les vacances.", options:["à","au","du","en"], correct:1, rule:"« le Liban » est masculin → « au Liban » (à + le). Pour aller dans un pays masculin : au.", why:["« à » s'emploie pour les villes.",null,"« du » exprime la provenance.","« en » s'emploie pour les pays féminins."] },
  { level:"A2", sentence:"Je te laisse, je dois aller à la poste, je veux ___ un colis en Espagne.", options:["donner","envoyer","recevoir","rendre"], correct:1, rule:"On va à la poste pour EXPÉDIER quelque chose : « envoyer un colis » est la collocation logique.", why:["« donner » se fait en main propre, pas à la poste pour l'étranger.",null,"« recevoir » est l'inverse — on ne va pas à la poste pour recevoir activement.","« rendre » signifie restituer, ce qui ne colle pas avec « en Espagne »."] },
  { level:"A2", sentence:"Camille ? Je la connais ___ dix ans.", options:["dans","de","depuis","il y a"], correct:2, rule:"« depuis » indique le point de départ d'une action qui CONTINUE jusqu'à présent. Je la connais depuis dix ans (et encore aujourd'hui).", why:["« dans » indique un moment futur (dans dix ans = plus tard).","« de » n'exprime pas la durée ici.",null,"« il y a » situe un événement ponctuel dans le passé (je l'ai rencontrée il y a dix ans), pas une continuité."] },
  { level:"B1", sentence:"Félix habite au 16e étage de la ___ située près du bureau de poste.", options:["chambre","cité","maison","tour"], correct:3, rule:"Un 16e étage implique un immeuble très haut : seule une « tour » a autant d'étages.", why:["« chambre » est une pièce, pas un bâtiment à étages.","« cité » est un ensemble de bâtiments, pas un seul avec 16 étages.","« maison » n'a pas 16 étages.",null] },
  { level:"B1", sentence:"Je suis ___ par tous les transports que je prends pour aller au travail. Quand j'arrive chez moi, j'ai juste assez d'énergie pour me coucher.", options:["déçue","fatiguée","distraite","suprise"], correct:1, rule:"Le contexte (manque d'énergie, envie de se coucher) indique l'épuisement : « fatiguée ».", why:["« déçue » exprime une déception, pas un manque d'énergie.",null,"« distraite » signifie inattentive.","« surprise » exprime l'étonnement (et le mot est mal orthographié)."] },
  { level:"C1", sentence:"J'ai demandé aux collègues quelle date conviendrait le mieux pour la réunion de service mais ___ que je propose, ils ne sont jamais satisfaits.", options:["où","quel","qui","quoi"], correct:3, rule:"« quoi que » (en deux mots) signifie « peu importe ce que ». Ici : peu importe ce que je propose. Suivi du subjonctif (propose).", why:["« où » concerne le lieu.","« quel » s'accorde et précède un nom (quelle date), pas un verbe seul.","« qui » concerne une personne.",null] },
  { level:"B2", sentence:"Ne t'inquiète pas, je te téléphonerai dès que l'avion ___.", options:["atterrirait","atterrisse","aura atterri","avait atterri"], correct:2, rule:"Après « dès que » avec une principale au futur, on emploie le FUTUR ANTÉRIEUR pour une action achevée avant l'autre : « aura atterri » (l'atterrissage précède le coup de fil).", why:["« atterrirait » est un conditionnel, incompatible ici.","« atterrisse » est un subjonctif ; on n'emploie pas le subjonctif après « dès que ».",null,"« avait atterri » est un plus-que-parfait, qui situe l'action dans le passé."] },
  { level:"B1", sentence:"On ne regardera pas la 6e chaîne ce soir ! Je déteste les émissions de télé-réalité ! ___ je veux bien voir le film documentaire sur la 2e.", options:["En effet,","En revanche,","Néanmoins,","Or,"], correct:1, rule:"« En revanche » marque une OPPOSITION/contraste entre deux préférences (je déteste ceci ↔ par contre j'aime cela).", why:["« En effet » confirme/explique, n'oppose pas.",null,"« Néanmoins » exprime une concession (malgré tout), moins adapté qu'un simple contraste de goûts.","« Or » introduit un argument nouveau dans un raisonnement, pas un contraste de goûts."] },
  { level:"B1", sentence:"Si ma sœur ne ___ pas systématiquement à la légère, elle n'aurait pas tant de défis à relever.", options:["s'engage","s'engageait","s'est engagée","s'était engagée"], correct:1, rule:"Hypothèse irréelle du présent : « Si » + IMPARFAIT, principale au conditionnel présent (n'aurait pas). Donc « s'engageait ».", why:["« s'engage » est le présent ; la concordance avec « aurait » exige l'imparfait.",null,"« s'est engagée » est un passé composé.","« s'était engagée » (plus-que-parfait) irait avec un conditionnel passé (n'aurait pas eu)."] },
  { level:"B2", sentence:"Je suis inquiète de l'___ qu'a Jason pour ce groupe, ça tient du fanatisme.", options:["accaparement","admiration","extase","inspiration"], correct:1, rule:"« admiration » (un attachement intense qui frôle le fanatisme) convient au sens. On admire un groupe.", why:["« accaparement » signifie monopoliser, sans rapport.",null,"« extase » est un ravissement ponctuel, trop fort et mal construit ici.","« inspiration » est ce qui pousse à créer, pas l'attachement décrit."] },
  { level:"A1", sentence:"À la montagne, en hiver, il ___ toujours très froid.", options:["est","fait","sent","va"], correct:1, rule:"Pour la météo, on utilise « il fait » : il fait froid, il fait chaud, il fait beau.", why:["« est » ne s'emploie pas pour la température ambiante (on ne dit pas « il est froid »).",null,"« sent » concerne l'odeur ou le toucher.","« va » s'emploie pour la santé (il va bien)."] },
  { level:"A2", sentence:"Quand j'étais étudiant, je travaillais comme serveur pour ___ mes études.", options:["acheter","gagner","offrir","payer"], correct:3, rule:"On « paie ses études » : régler le coût des études. Collocation naturelle.", why:["« acheter » ne se dit pas avec « études ».","« gagner » se dit pour de l'argent (gagner sa vie), pas « gagner ses études ».","« offrir » signifie donner gratuitement.",null] },
  { level:"A1", sentence:"J'adore le cinéma ___ je n'y vais pas souvent parce que j'ai trop de travail.", options:["alors","donc","et","mais"], correct:3, rule:"« mais » marque l'OPPOSITION entre aimer le cinéma et ne pas y aller. Contraste logique.", why:["« alors » exprime une conséquence.","« donc » exprime aussi une conséquence logique.","« et » ajoute sans opposer.",null] },
  { level:"B1", sentence:"L'émission musicale ___ ce journaliste anime sur TV5 est vraiment passionnante.", options:["dont","où","que","qui"], correct:2, rule:"« que » est pronom relatif COD : « ce journaliste anime [l'émission] » → l'émission QUE ce journaliste anime.", why:["« dont » remplace un complément introduit par « de ».","« où » indique le lieu ou le temps.",null,"« qui » est sujet (qui anime), mais ici le sujet est « ce journaliste »."] },
  { level:"B2", sentence:"Les candidats à l'élection présidentielle ont multiplié les ___ à la presse pour séduire les électeurs.", options:["déclarations","justifications","intentions","informations"], correct:0, rule:"« faire des déclarations à la presse » est la collocation usuelle pour s'exprimer publiquement.", why:[null,"« justifications » suppose une accusation préalable.","« intentions » ne se « multiplient » pas auprès de la presse.","« informations » seraient données par la presse, non aux candidats."] },
  { level:"C1", sentence:"Les professeurs Watson, Crick et Wilkins ont reçu en 1962 le prix Nobel... à qui ils la ___ quand elle travaillait dans leur laboratoire.", options:["dérobaient","dérobent","dérobèrent","déroberont"], correct:2, rule:"Récit historique daté (1962) → PASSÉ SIMPLE pour une action ponctuelle achevée : « dérobèrent ».", why:["« dérobaient » (imparfait) exprime une action répétée/en cours, pas l'acte ponctuel.","« dérobent » est le présent.",null,"« déroberont » est le futur."] },
  { level:"B2", sentence:"La commission a précisé que les financements culturels européens ___ des artistes sont liés à leurs compétences...", options:["au fond","au lieu","au moyen","au profit"], correct:3, rule:"« au profit de » signifie « au bénéfice de ». Les financements sont accordés au profit (au bénéfice) des artistes.", why:["« au fond » signifie en réalité/au final.","« au lieu (de) » signifie à la place de.","« au moyen (de) » signifie grâce à un outil.",null] },
  { level:"B2", sentence:"...l'actualité des prochains jours sera ___ orientée autour de sujets politiques.", options:["cependant","certes","pourtant","davantage"], correct:3, rule:"« davantage » signifie « plus, dans une plus grande mesure ». L'actualité sera davantage (plus) orientée vers la politique.", why:["« cependant » exprime une opposition.","« certes » concède un point.","« pourtant » marque une contradiction.",null] },
  { level:"C1", sentence:"Malgré l'invitation et le plan que je lui avais envoyés, Jacques n'a pas ___ se déplacer pour la cérémonie.", options:["agréé","concédé","daigné","toléré"], correct:2, rule:"« daigner » = condescendre à faire quelque chose. « n'a pas daigné se déplacer » = il n'a même pas pris la peine de venir.", why:["« agréé » signifie accepter/approuver, et ne se construit pas ainsi.","« concédé » signifie admettre/céder.",null,"« toléré » signifie supporter, sens incompatible ici."] },
  { level:"C1", sentence:"...les mesures du gouvernement en faveur de la parité au travail ___ l'intégralité des milieux socio-professionnels.", options:["élargissent","étendent","recouvrent","remplissent"], correct:2, rule:"« recouvrir » au sens figuré = couvrir, englober la totalité d'un domaine. Les mesures recouvrent (englobent) tous les milieux.", why:["« élargissent » signifie rendre plus large (on élargit une mesure, pas un milieu).","« étendent » a besoin d'un complément de destination (étendre à).",null,"« remplissent » se dit d'un contenant, sens concret inadapté."] },
  { level:"A1", sentence:"Je m'appelle Gian. Et toi, ___ tu t'appelles ?", options:["comment","pourquoi","quand","qui"], correct:0, rule:"Pour demander un nom, on emploie « comment » : Comment tu t'appelles ? (= quel est ton nom).", why:[null,"« pourquoi » demande une raison.","« quand » demande un moment.","« qui » demande l'identité d'une personne mais ne se construit pas avec « s'appeler » de cette façon."] },
  { level:"A2", sentence:"Attention ! La séance de 18 heures pour le film « Folie douce » est ___. Il reste des places pour la séance de 20 heures.", options:["complète.","entière.","nombreuse","totale."], correct:0, rule:"Une séance « complète » = toutes les places sont vendues (plus de place disponible). Sens attendu vu le contexte.", why:[null,"« entière » signifie non divisée, pas « pleine ».","« nombreuse » qualifie une quantité de gens, pas une séance.","« totale » signifie absolue, ne se dit pas d'une séance pleine."] },
  { level:"A1", sentence:"Avec le programme « Jeunes d'Europe », finissez ___ études à l'étranger.", options:["leurs","mes","ses","vos"], correct:3, rule:"L'impératif « finissez » est à la 2e personne du pluriel (vous) → l'adjectif possessif correspondant est « vos ».", why:["« leurs » renvoie à « ils/elles ».","« mes » renvoie à « je ».","« ses » renvoie à « il/elle ».",null] },
  { level:"A2", sentence:"Venez profiter des promotions ! Cette semaine, trois paquets de café ___ le prix de deux !", options:["avec","par","pour","selon"], correct:2, rule:"« pour » exprime l'échange/le prix : trois paquets POUR le prix de deux (on obtient 3 en payant 2).", why:["« avec » indique l'accompagnement.","« par » indique le moyen ou la répartition.",null,"« selon » indique la conformité."] },
  { level:"A2", sentence:"Salut Léa ! ...J'attends les résultats de mon examen demain et je me sens vraiment ___. J'ai besoin de sortir un peu !", options:["surprise","déçue","désolée","nerveuse"], correct:3, rule:"Attendre des résultats provoque de l'anxiété : « nerveuse » (tendue, stressée) est l'émotion logique.", why:["« surprise » suppose un événement inattendu déjà arrivé.","« déçue » suppose un résultat déjà connu et négatif.","« désolée » exprime le regret.",null] },
  { level:"B1", sentence:"Cet après-midi, aussitôt après les déclarations de la direction à la presse, le syndicat ___ son plan d'action que les employés attendent avec impatience.", options:["annonçait","annonce","annoncera","annoncerait"], correct:2, rule:"L'action est à venir (cet après-midi, attendue avec impatience) → FUTUR simple : « annoncera ».", why:["« annonçait » est un imparfait (passé).","« annonce » (présent) ne rend pas l'idée d'une action attendue plus tard.",null,"« annoncerait » est un conditionnel (incertitude/hypothèse)."] },
  { level:"B1", sentence:"Une fois votre document sélectionné, vous pouvez ___ la clé USB sur le port prévu à cet effet afin d'enregistrer votre document.", options:["allumer","cliquer","insérer","taper"], correct:2, rule:"On « insère » une clé USB dans un port : introduire physiquement l'objet. Collocation technique correcte.", why:["« allumer » se dit d'un appareil, pas d'une clé qu'on branche.","« cliquer » se fait avec une souris.",null,"« taper » se dit au clavier."] },
  { level:"B2", sentence:"Nous continuons à marcher 2 h chaque jour ___ nous sommes âgés maintenant.", options:["afin que","bien que","même si","quoique"], correct:2, rule:"« même si » + INDICATIF (nous sommes) exprime la concession. Ici l'indicatif « sommes » impose « même si » plutôt que les conjonctions à subjonctif.", why:["« afin que » exprime le but + subjonctif.","« bien que » exige le subjonctif (bien que nous soyons).",null,"« quoique » exige aussi le subjonctif (quoique nous soyons)."] },
  { level:"B2", sentence:"...Les boutiques accueillent une clientèle ___ de plus en plus nombreuse.", options:["analogue","disparate","dissemblable","homogène"], correct:1, rule:"Le texte dit que TOUTES les catégories sociales sont concernées → une clientèle « disparate » (variée, hétérogène). Le sens du texte appelle la diversité.", why:["« analogue » signifie semblable.",null,"« dissemblable » s'emploie pour comparer deux choses, pas pour qualifier une variété.","« homogène » signifie uniforme — le contraire du sens voulu."] },
  { level:"C1", sentence:"Le nouveau président du parti demande à ses alliés de mettre en ___ les querelles intestines, afin de créer une unité nouvelle et mettre fin aux rivalités internes.", options:["abyme","exergue","garde","sourdine"], correct:3, rule:"« mettre en sourdine » = atténuer, faire taire. Il veut faire taire les querelles. Expression figée.", why:["« mettre en abyme » = représenter une œuvre dans l'œuvre.","« mettre en exergue » = mettre en valeur (le contraire du sens voulu).","« mettre en garde » = avertir d'un danger.",null] },
  { level:"A1", sentence:"Chers voisins, je fais une petite fête samedi soir, vous pouvez ___ chez moi pour boire un verre. Alfonso, votre voisin du 1er, porte 25.", options:["aller","partir","sortir","venir"], correct:3, rule:"« venir chez quelqu'un » exprime le mouvement vers le lieu où se trouve la personne qui parle (l'hôte invite chez lui).", why:["« aller » s'éloigne du locuteur, pas vers lui.","« partir » signifie quitter un lieu.","« sortir » signifie aller dehors.",null] },
  { level:"A2", sentence:"___ un rendez-vous avec M. Bodin, il faut téléphoner à son secrétariat.", options:["Depuis","Dans","Pendant","Pour"], correct:3, rule:"« Pour » introduit le but : pour obtenir un rendez-vous, il faut téléphoner.", why:["« Depuis » marque le point de départ dans le temps.","« Dans » marque un délai futur.","« Pendant » marque la durée.",null] },
  { level:"A2", sentence:"Félicitations à Lucie Décosse : mercredi, elle est devenue ___ olympique de judo pour les moins de 70 kg.", options:["championne","joueuse","participante","sportive"], correct:0, rule:"« championne » désigne celle qui gagne le titre olympique : sens et collocation corrects.", why:[null,"« joueuse » est trop général.","« participante » n'implique pas la victoire.","« sportive » est un adjectif/nom général, pas le titre."] },
  { level:"A2", sentence:"Je suis ___ car il n'y a plus de places pour le festival de musique traditionnelle à Saint-Malo et je voulais y aller.", options:["déçue","jalouse","nerveuse","pessimiste"], correct:0, rule:"« déçue » exprime la frustration de ne pas pouvoir faire ce qu'on voulait (plus de places).", why:[null,"« jalouse » concerne l'envie envers autrui.","« nerveuse » est l'anxiété.","« pessimiste » est une attitude générale, pas la réaction ponctuelle."] },
  { level:"A2", sentence:"Les années précédentes, d'après les sondages, les Français ___ environ 10 % de leur salaire mensuel aux cadeaux de Noël. Cette année, ce chiffre a baissé.", options:["réservaient","réservent","réserveraient","réserveront"], correct:0, rule:"Action habituelle dans le passé (« les années précédentes ») → imparfait « réservaient ».", why:[null,"« réservent » est le présent.","« réserveraient » est le conditionnel.","« réserveront » est le futur."] },
  { level:"A2", sentence:"Le Festival des arts de la rue de Ramonville s'est achevé la semaine dernière. Il a ___ un public encore plus important que l'année passée.", options:["accroché","attiré","convié","retenu"], correct:1, rule:"Le passé composé « a attiré » exprime une action accomplie : le festival a attiré du public.", why:["« accroché » ne se dit pas d'un public.",null,"« convié » signifie inviter formellement.","« retenu » signifie garder, sens inadapté."] },
  { level:"B2", sentence:"Le député réclame la fermeture provisoire de l'usine, même s'il n'y a eu que deux ___ techniques sans gravité.", options:["catastrophes","événements","incidents","tragédies"], correct:2, rule:"« incidents » désigne de petits événements fâcheux sans gravité : exactement le sens voulu.", why:["« catastrophes » sont graves, contredisant « sans gravité ».","« événements » est neutre, trop vague.",null,"« tragédies » sont très graves."] },
  { level:"B1", sentence:"Aux occupants de l'immeuble : déposez sur le trottoir, jeudi matin avant 8 heures, les objets encombrants dont vous souhaitez vous débarrasser pour que les éboueurs les ___ Merci de votre compréhension. Le syndic.", options:["raccordent.","ramassent.","ramènent.","rassemblent."], correct:1, rule:"« ramasser » = enlever/collecter les objets : ce que font les éboueurs. Subjonctif « ramassent » après « pour que ».", why:["« raccorder » signifie relier.",null,"« ramener » signifie rapporter.","« rassembler » signifie regrouper, pas enlever."] },
  { level:"B2", sentence:"Ce documentaire sur les internats est d'une grande qualité : l'___ dans la vie quotidienne des élèves est passionnante.", options:["identification","immersion","inscription","intuition"], correct:1, rule:"« immersion » = plongée totale dans un milieu : l'immersion dans la vie des élèves.", why:["« identification » signifie reconnaître.",null,"« inscription » signifie s'enregistrer.","« intuition » est un pressentiment."] },
  { level:"C1", sentence:"En novembre, plus de 100 000 personnes qui n'étaient pas d'accord avec le nouveau projet loi du gouvernement avaient ___ dans plusieurs villes de France.", options:["battu le pavé","fait la fine bouche","joué avec le feu","tourné les talons"], correct:0, rule:"« battre le pavé » est une expression idiomatique signifiant manifester dans la rue.", why:[null,"« faire la fine bouche » = se montrer difficile.","« jouer avec le feu » = prendre des risques.","« tourner les talons » = partir."] },
  { level:"A1", sentence:"Je voudrais un ___ de pommes.", options:["degré","kilo","litre","mètre"], correct:1, rule:"« kilo » est l'unité de poids pour acheter des pommes : un kilo de pommes.", why:["« degré » mesure la température/l'angle.",null,"« litre » mesure les liquides.","« mètre » mesure la longueur."] },
  { level:"A1", sentence:"Isabelle, je t'attends au café, ___ arrives-tu ?", options:["combien","pourquoi","quand","qui"], correct:2, rule:"« quand » interroge sur le moment de l'arrivée.", why:["« combien » interroge sur la quantité.","« pourquoi » sur la raison.",null,"« qui » sur la personne."] },
  { level:"A2", sentence:"Servez-vous ! Prenez un autocollant et collez-___ sur votre voiture. Cela aidera notre association.", options:["en","le","lui","y"], correct:1, rule:"« le » est le COD qui remplace « un autocollant » : collez-le.", why:["« en » remplace un complément avec « de ».",null,"« lui » est un COI.","« y » remplace un lieu."] },
  { level:"B1", sentence:"Nous vous ___ que la réunion de rentrée aura lieu demain à 15h30, dans l'auditorium. La direction.", options:["conseillons","demandons","proposons","rappelons"], correct:3, rule:"« rappeler que » = redire une information. La direction rappelle l'horaire de la réunion.", why:["« conseiller » suggère.","« demander » sollicite.","« proposer » offre un choix.",null] },
  { level:"B1", sentence:"La nouvelle mode fait débat. Beaucoup de personnes trouvent que ces jeunes s'habillent n'importe ___", options:["comment.","où.","quand.","quoi."], correct:0, rule:"« n'importe comment » = sans soin, de n'importe quelle manière. Locution figée.", why:[null,"« où » concerne le lieu.","« quand » le temps.","« quoi » la chose."] },
  { level:"B1", sentence:"Emma, si on ___ rendre visite à tes parents le week-end prochain ? Qu'est-ce que tu en penses ?", options:["allait","ira","irait","va"], correct:0, rule:"« si on allait » : l'imparfait après « si » exprime une suggestion/proposition.", why:[null,"« ira » est le futur.","« irait » le conditionnel.","« va » le présent."] },
  { level:"B1", sentence:"Je suis heureux car j'ai réussi à ___ mes difficultés. J'ai rendu le travail à temps.", options:["déplacer","retourner","surmonter","transposer"], correct:2, rule:"« surmonter » = vaincre une difficulté : réussir à surmonter ses difficultés.", why:["« déplacer » = bouger.","« retourner » = revenir.",null,"« transposer » = transférer ailleurs."] },
  { level:"B1", sentence:"Aujourd'hui, huit salariés sur dix disent qu'ils aimeraient changer de métier, ___ peu d'entre eux le font.", options:["ainsi","alors","comme","pourtant"], correct:3, rule:"« pourtant » marque l'opposition : ils veulent changer, pourtant peu le font.", why:["« ainsi » exprime la conséquence.","« alors » la conséquence/temps.","« comme » la comparaison/cause.",null] },
  { level:"C1", sentence:"Au début du XXème siècle, le juriste Raymond Carré de Malberg estime que le droit public français permet de ___ les contours d'une théorie générale de l'État.", options:["contempler","dessiner","remarquer","souligner"], correct:1, rule:"« dessiner les contours » = esquisser, tracer les grandes lignes d'une théorie. Sens figuré.", why:["« contempler » = regarder.",null,"« remarquer » = constater.","« souligner » = mettre en valeur."] },
  { level:"C1", sentence:"Course de l'Ultra-Trail du Mont-Blanc : la surprise pourrait venir du coureur espagnol. ___ qu'il se soit entraîné comme il l'a annoncé, il pourrait être propulsé sur la plus haute marche du podium.", options:["À moins","À supposer","Nul doute","Sans compter"], correct:1, rule:"« À supposer que » + subjonctif (soit) introduit une hypothèse.", why:["« À moins que » exprime une condition restrictive.",null,"« Nul doute » affirme une certitude.","« Sans compter » ajoute un élément."] },
  { level:"A2", sentence:"Pour rentrer à la maison, je passe ___ le parc.", options:["par","pour","sur","vers"], correct:0, rule:"« passer par » = emprunter un chemin/lieu : je passe par le parc.", why:[null,"« pour » exprime le but.","« sur » la position.","« vers » la direction approximative."] },
  { level:"A1", sentence:"Avant de sortir le soir entre amis, les jeunes ___ dans la salle de bains pendant plusieurs heures.", options:["entrent","habitent","restent","vivent"], correct:2, rule:"« rester » = demeurer dans un lieu : ils restent dans la salle de bains.", why:["« entrer » = pénétrer.","« habiter » = résider.",null,"« vivre » = exister/résider."] },
  { level:"A1", sentence:"Pour la soirée d'Aurélie, Adrien fait le dessert. Il prépare un gâteau ___ chocolat.", options:["au","de","du","en"], correct:0, rule:"« au » (à + le) introduit le parfum/la garniture : un gâteau au chocolat.", why:[null,"« de » ne s'emploie pas ainsi.","« du » serait partitif, inadapté.","« en » indique la matière, pas le parfum."] },
  { level:"A1", sentence:"Je dois ___ avant 8h de la maison pour être à l'heure au travail.", options:["aller","entrer","partir","venir"], correct:2, rule:"« partir » = quitter un lieu : partir de la maison avant 8h.", why:["« aller » a besoin d'une destination.","« entrer » = pénétrer.",null,"« venir » = se rapprocher du locuteur."] },
  { level:"A2", sentence:"Le dernier épisode de « Harry Potter » est disponible en version française ___ 2011.", options:["après","depuis","pendant","pour"], correct:1, rule:"« depuis » marque le point de départ d'une situation qui dure : disponible depuis 2011.", why:["« après » situe après un événement.",null,"« pendant » marque la durée.","« pour » une durée prévue."] },
  { level:"B1", sentence:"Comme vous le savez, pour ___ la forme, il faut faire du sport régulièrement.", options:["changer","donner","garder","prendre"], correct:2, rule:"« garder la forme » = rester en bonne condition physique. Collocation figée.", why:["« changer » ne convient pas.","« donner » non plus.",null,"« prendre » ne se dit pas avec « la forme » ainsi."] },
  { level:"B1", sentence:"Il a raté ses examens et ___ il a beaucoup travaillé.", options:["en effet","en revanche","par ailleurs","pourtant"], correct:3, rule:"« pourtant » marque l'opposition : il a échoué, pourtant il a travaillé.", why:["« en effet » confirme.","« en revanche » oppose mais maladroit ici.","« par ailleurs » ajoute.",null] },
  { level:"B2", sentence:"Après avoir été ___ dans de nombreuses villes, l'exposition Africa Remix est enfin arrivée à Johannesburg en Afrique du Sud.", options:["accueillie","découverte","marquée","représentée"], correct:0, rule:"« accueillie » : participe passé féminin accordé avec « l'exposition » (féminin). Sens : reçue dans des villes.", why:[null,"« découverte » change le sens.","« marquée » ne convient pas.","« représentée » est moins précis."] },
  { level:"B1", sentence:"Les pesticides chimiques sont maintenant interdits dans les ___ verts de la capitale.", options:["domaines","endroits","espaces","lieux"], correct:2, rule:"« espaces verts » est l'expression consacrée pour les zones de verdure d'une ville.", why:["« domaines » est trop vaste.","« endroits » est vague.",null,"« lieux » est vague."] },
  { level:"B2", sentence:"La direction du magasin a affirmé qu'elle voulait rénover les locaux pour en faire un magasin populaire et attractif. Les syndicats ___ à eux, voient ces investissements comme un gaspillage de capitaux.", options:["conformément","eu égard","par rapport","quant"], correct:3, rule:"« quant à » = en ce qui concerne : quant à eux (les syndicats).", why:["« conformément » = en accord avec.","« eu égard » = en considération de.","« par rapport » = en comparaison.",null] },
  { level:"A2", sentence:"J'aime beaucoup les enfants, plus tard je voudrais être ___", options:["dentiste.","enseignant.","footballeur.","photographe."], correct:1, rule:"« enseignant » = celui qui enseigne : logique pour qui aime les enfants.", why:["« dentiste » sans rapport.",null,"« footballeur » sans rapport.","« photographe » sans rapport."] },
  { level:"A1", sentence:"Vendredi soir, on pourrait ___ un film chez moi. Qu'est-ce que tu en penses ?", options:["essayer","préparer","regarder","travailler"], correct:2, rule:"« regarder un film » est la collocation correcte.", why:["« essayer » ne convient pas.","« préparer » non plus.",null,"« travailler » non plus."] },
  { level:"A2", sentence:"J'ai vu hier soir un ___ film.", options:["anglais","drôle","policier","vieux"], correct:3, rule:"« vieux » se place avant le nom : un vieux film. (Adjectif court et courant.)", why:["« anglais » se place après le nom.","« drôle » irait après aussi ici.","« policier » se place après.",null] },
  { level:"B1", sentence:"Diane, je préfère que tu ne ___ pas avec moi chez le dentiste. Il est toujours en retard et tu perdrais ton temps.", options:["venais","viendras","viennes","viens"], correct:2, rule:"Après « préférer que », on emploie le subjonctif : que tu viennes.", why:["« venais » est l'imparfait.","« viendras » le futur.",null,"« viens » l'indicatif présent."] },
  { level:"B1", sentence:"J'ai eu une allergie, je ne mangerai jamais ___ de fraises.", options:["pas","plus","rien","sans"], correct:1, rule:"« ne... plus jamais » : « plus » exprime l'arrêt définitif après l'allergie.", why:["« pas » serait redondant avec jamais.",null,"« rien » est un pronom.","« sans » est une préposition."] },
  { level:"B2", sentence:"Paula n'a pas été prise pour ce poste ___ lequel elle comptait vraiment. Elle avait pourtant mis toutes les chances de son côté.", options:["dans","par","pour","sur"], correct:3, rule:"« compter sur » = se fier à : le poste sur lequel elle comptait.", why:["« dans » ne convient pas.","« par » non plus.","« pour » non plus.",null] },
  { level:"B1", sentence:"Qui est-il ? Qui est ce gagnant du loto qui ___ de donner 50 millions d'euros à une dizaine de grandes associations nationales ?", options:["admet","permet","promet","soumet"], correct:2, rule:"« promettre de » = s'engager à : le gagnant qui promet de donner.", why:["« admettre » = reconnaître.","« permettre » = autoriser.",null,"« soumettre » = présenter."] },
  { level:"A2", sentence:"Les milliers de cadenas qui étaient accrochés par les amoureux sur les ponts parisiens ___ des problèmes de sécurité et d'esthétisme : ils ont été retirés.", options:["donnaient","impliquaient","offraient","posaient"], correct:3, rule:"Imparfait « posaient » : situation durable dans le passé (les cadenas posaient problème).", why:["« donnaient » ne se dit pas « donner des problèmes ».","« impliquaient » est possible mais moins idiomatique.","« offraient » a un sens positif.",null] },
  { level:"A2", sentence:"Son souhait ___ que ses enfants ne déménagent pas aussi loin. Elle aurait été heureuse de les garder auprès d'elle encore un peu.", options:["a été","est","était","sera"], correct:2, rule:"Imparfait « était » exprime un souhait dans le passé non réalisé (contexte au conditionnel passé).", why:["« a été » est un passé composé.","« est » le présent.",null,"« sera » le futur."] },
  { level:"B2", sentence:"Le musée d'Orsay organise une grande rétrospective autour de l'œuvre du peintre Claude Monet. Il faut ___ sur l'occasion pour redécouvrir l'univers de cet artiste merveilleux.", options:["bondir","courir","marcher","sauter"], correct:3, rule:"« sauter sur l'occasion » = saisir vite une opportunité. Expression idiomatique.", why:["« bondir » ne forme pas l'expression.","« courir » non plus.","« marcher » non plus.",null] },
  { level:"A1", sentence:"Quand vous voyagez, vous pouvez aussi regarder TV5MONDE ___ votre hôtel !", options:["avec","dans","sur","vers"], correct:1, rule:"« dans votre hôtel » : « dans » indique le lieu où l'on se trouve.", why:["« avec » l'accompagnement.",null,"« sur » la surface.","« vers » la direction."] },
  { level:"A1", sentence:"Christophe, ta photographie est choisie par le jury du concours « Photo de l'année ». Tu es en finale. C'est très ___ Je te félicite !", options:["bien !","formidable !","génial !","super !"], correct:0, rule:"« C'est très bien ! » : « bien » est l'adverbe attendu après « très » dans cette félicitation.", why:[null,"« formidable » ne se combine pas avec « très » naturellement ici.","« génial » non plus.","« super » non plus."] },
  { level:"A2", sentence:"Patricia travaille dans cette entreprise ___ dix ans et elle aime beaucoup ses collègues.", options:["après","depuis","en","pendant"], correct:1, rule:"« depuis » marque la durée continue jusqu'à présent : travaille depuis dix ans.", why:["« après » situe après un point.",null,"« en » ne marque pas la durée continue.","« pendant » marque une durée révolue."] },
  { level:"B1", sentence:"C'est sympa que tu viennes pour le pique-nique. Est-ce que tu ___ apporter du fromage et du pain, s'il te plaît ?", options:["devrais","ferais","pourrais","voudrais"], correct:2, rule:"« pourrais » (conditionnel de politesse) pour une demande polie : pourrais-tu apporter ?", why:["« devrais » exprime l'obligation.","« ferais » est vague.",null,"« voudrais » exprime un souhait du locuteur, pas une demande à l'autre."] },
  { level:"B1", sentence:"Je n'ai pas envie d'aller voir la comédie que tu proposes ___ je veux bien aller voir un policier.", options:["car","donc","en effet","par contre"], correct:3, rule:"« par contre » marque l'opposition entre deux préférences.", why:["« car » introduit une cause.","« donc » une conséquence.","« en effet » une confirmation.",null] },
  { level:"B2", sentence:"Les maires des grandes villes de France ___ une véritable importance aux transports.", options:["accordent","appliquent","assurent","avouent"], correct:0, rule:"« accorder de l'importance à » = attribuer de la valeur. Collocation figée.", why:[null,"« appliquer » ne se dit pas avec « importance ».","« assurer » non plus.","« avouer » signifie confesser."] },
  { level:"B1", sentence:"Jean a trouvé un nouvel emploi en tant que commercial. Il va travailler dans toute l'Europe et sera souvent en ___ professionnel.", options:["circuit","déplacement","marche","mouvement"], correct:1, rule:"« déplacement professionnel » = voyage pour le travail. Collocation correcte.", why:["« circuit » est un parcours touristique.",null,"« marche » = action de marcher.","« mouvement » est trop général."] },
  { level:"B2", sentence:"Je voulais parler à Justine Belgrand, mais comme il est déjà 19h30, elle a dû partir, j'en ai bien ___", options:["assez.","envie.","marre.","peur."], correct:3, rule:"« en avoir peur » : « j'en ai bien peur » = je le crains. Expression figée.", why:["« assez » → en avoir assez = être lassé, sens différent.","« envie » → en avoir envie, sens positif.","« marre » → familier, sens de lassitude.",null] },
  { level:"C1", sentence:"J'ai eu de la chance ! Il s'en est fallu de peu que ___ mon avion.", options:["je perde","je prenne","je rate","j'échappe"], correct:2, rule:"Après « il s'en est fallu de peu que », on emploie le subjonctif : que je rate.", why:["« je perde » : le verbe attendu est « rater » pour le sens (manquer l'avion).","« je prenne » a un sens opposé.",null,"« j'échappe » ne se construit pas ainsi."] },
  { level:"C1", sentence:"Vous avez rendu votre rapport en faisant ___ mes remarques. C'est intolérable !", options:["cas de","fi de","mine de","montre de"], correct:1, rule:"« faire fi de » = ne pas tenir compte de : faire fi de mes remarques. Expression figée.", why:["« faire cas de » = au contraire tenir compte.",null,"« faire mine de » = faire semblant.","« faire montre de » = montrer."] },
  { level:"A1", sentence:"Vous voulez connaître la météo ___ le monde ? Rendez-vous sur le site Internet de TV5.", options:["avec","dans","par","sur"], correct:1, rule:"« dans le monde » : « dans » pour situer à l'échelle mondiale.", why:["« avec » l'accompagnement.",null,"« par » le moyen.","« sur » la surface."] },
  { level:"B1", sentence:"Ces bottes sont trop petites ! Tu devrais prendre la ___ au-dessus.", options:["chaussure","couture","mesure","pointure"], correct:3, rule:"« pointure » désigne la taille des chaussures (bottes). Mot précis.", why:["« chaussure » est l'objet, pas la taille.","« couture » sans rapport.","« mesure » est trop général.",null] },
  { level:"A2", sentence:"Les employés en colère ___ depuis mardi et les bus ne circulent pas.", options:["cherchent un travail","prennent leur retraite","signent un contrat","sont en grève"], correct:3, rule:"« être en grève » : les employés en colère sont en grève (bus arrêtés).", why:["« cherchent un travail » contredit le contexte.","« prennent leur retraite » non plus.","« signent un contrat » non plus.",null] },
  { level:"B1", sentence:"Je suis arrivée à l'hôtel lundi, à quatorze heures. Mon amie, elle, ___ déjà arrivée depuis deux jours. Elle connaissait tout le monde.", options:["est","était","sera","serait"], correct:1, rule:"Imparfait « était » (sous-entendu était arrivée) : action antérieure dans le passé.", why:["« est » est le présent.",null,"« sera » le futur.","« serait » le conditionnel."] },
  { level:"A2", sentence:"Je préfère visiter des pays où ___", options:["j'ai lu un bon guide.","j'apprécie le climat.","je connais la langue.","je peux parler français."], correct:3, rule:"« où » introduit une relative de lieu : des pays où je peux parler français.", why:["« j'ai lu un bon guide » ne se relie pas par « où » au sens voulu.","« j'apprécie le climat » idem.","« je connais la langue » idem.",null] },
  { level:"A2", sentence:"Suite au succès de notre nouveau produit, j'ai le plaisir de vous annoncer que notre entreprise est ___ compétitive sur le marché mondial.", options:["de loin en loin","de mieux en mieux","de moins en moins","de plus en plus"], correct:3, rule:"« de plus en plus » exprime une progression croissante : de plus en plus compétitive.", why:["« de loin en loin » = rarement.","« de mieux en mieux » concerne la qualité, possible mais moins précis.","« de moins en moins » = décroissant, sens opposé.",null] },
  { level:"B2", sentence:"Mes parents sont d'accord pour que je sorte samedi soir ___ mes devoirs soient terminés.", options:["à condition que","afin que","selon que","si bien que"], correct:0, rule:"« à condition que » + subjonctif (soient) exprime la condition.", why:[null,"« afin que » exprime le but.","« selon que » exprime l'alternative.","« si bien que » la conséquence."] },
  { level:"B1", sentence:"Inutile de se dépêcher : le rendez-vous de quinze heures a été ___ à seize heures !", options:["attardé","confirmé","rejeté","reporté"], correct:3, rule:"« reporté » = déplacé à une date ultérieure : reporté à seize heures.", why:["« attardé » ne se dit pas d'un rendez-vous.","« confirmé » = maintenu.","« rejeté » = refusé.",null] },
  { level:"C1", sentence:"De toute façon, ___ je fasse, vous ne semblez pas intéressés par ce cours de sciences !", options:["bien que","pour que","quoi que","sans que"], correct:2, rule:"« quoi que » (en deux mots) = peu importe ce que. Suivi du subjonctif (fasse).", why:["« bien que » = concession.","« pour que » = but.",null,"« sans que » = absence."] },
  { level:"C1", sentence:"Vous devez rendre votre copie avant la fin des deux heures qui vous sont ___", options:["consacrées.","décernées.","imparties.","rétribuées."], correct:2, rule:"« imparties » = accordées, allouées (un temps imparti). Terme précis.", why:["« consacrées » = dédiées, moins précis.","« décernées » = pour un prix.",null,"« rétribuées » = payées."] },
  { level:"A1", sentence:"Je vais à la ___ je dois acheter une baguette.", options:["boucherie,","boulangerie,","pharmacie,","poissonnerie,"], correct:1, rule:"« boulangerie » : on y achète une baguette. Collocation logique.", why:["« boucherie » vend de la viande.",null,"« pharmacie » des médicaments.","« poissonnerie » du poisson."] },
  { level:"A1", sentence:"Il ___ tard chez lui le soir, dîne rapidement et va se coucher.", options:["rentre","retourne","sort","va"], correct:0, rule:"« rentrer » = revenir chez soi : il rentre tard chez lui le soir.", why:[null,"« retourner » a besoin d'un lieu précis.","« sortir » = aller dehors.","« va » est trop vague."] },
  { level:"A2", sentence:"Julien est assis trop près du feu, il va se ___", options:["brûler.","casser.","couper.","mouiller."], correct:0, rule:"« se brûler » : près du feu, on risque de se brûler.", why:[null,"« se casser » sans rapport.","« se couper » sans rapport.","« se mouiller » sans rapport."] },
  { level:"B1", sentence:"Tous les cinq ans, les citoyens de chaque pays membre de l'Union ___ leurs députés au parlement européen.", options:["adoptent","élisent","nomment","votent"], correct:1, rule:"« élire » = choisir par vote : les citoyens élisent leurs députés.", why:["« adopter » = approuver un texte.",null,"« nommer » = désigner sans vote.","« voter » est intransitif ici (on vote, on n'« vote » pas les députés)."] },
  { level:"B1", sentence:"Dans le « Guide de l'étudiant », vous trouverez des informations utiles sur les activités sportives et culturelles qui sont ___ à l'université.", options:["données","promises","proposées","vendues"], correct:2, rule:"« proposées » : participe passé féminin pluriel accordé avec « activités ». Sens : offertes.", why:["« données » change le sens.","« promises » non plus.",null,"« vendues » non plus."] },
  { level:"B2", sentence:"Si vous aviez appelé l'agence de tourisme avant de partir, vous ___ su que votre vol était annulé.", options:["aurez","auriez","avez","aviez"], correct:1, rule:"« auriez su » : conditionnel passé dans une hypothèse avec « si » + plus-que-parfait.", why:["« aurez » est le futur antérieur.",null,"« avez » le présent.","« aviez » l'imparfait."] },
  { level:"B1", sentence:"Le directeur de l'entreprise a annoncé qu'il comprenait les demandes de hausse de salaire des employés. ___ il n'a accordé aucune augmentation.", options:["D'ailleurs,","De plus,","En effet,","Pourtant,"], correct:3, rule:"« Pourtant » marque l'opposition : il comprenait, pourtant il n'a rien accordé.", why:["« D'ailleurs » ajoute un argument.","« De plus » ajoute.","« En effet » confirme.",null] },
  { level:"A2", sentence:"Au voleur ! ___ la sécurité !", options:["Alertez","Rencontrez","Renseignez","Signalez"], correct:0, rule:"« Alerter » = avertir d'un danger : alertez la sécurité.", why:[null,"« Rencontrer » = voir quelqu'un.","« Renseigner » = informer.","« Signaler » est proche mais « alerter la sécurité » est l'expression d'urgence."] },
  { level:"B2", sentence:"Soyez vigilant lorsque vous préparez les factures ___ personne ne puisse mettre notre entreprise en cause.", options:["bien que","de sorte que","pourvu que","selon que"], correct:1, rule:"« de sorte que » + subjonctif (puisse) exprime le but/la conséquence voulue.", why:["« bien que » = concession.",null,"« pourvu que » = condition souhaitée.","« selon que » = alternative."] },
  { level:"C1", sentence:"Après des mois de ___ judiciaire, ce procès retentissant va enfin connaître son dénouement.", options:["feuilleton","rubrique","série","tournage"], correct:0, rule:"« feuilleton judiciaire » = affaire qui dure et tient en haleine, comme un feuilleton.", why:[null,"« rubrique » = section de journal.","« série » est proche mais « feuilleton » est l'expression consacrée.","« tournage » = filmer."] },
  { level:"A1", sentence:"J'habite près de la maison ___", options:["bleue.","grande.","jolie.","vieille."], correct:0, rule:"« bleue » : adjectif de couleur placé après le nom (la maison bleue).", why:[null,"« grande » se place souvent avant.","« jolie » se place avant.","« vieille » se place avant."] },
  { level:"A1", sentence:"Demain, le directeur de l'entreprise présentera son projet ___ ses employés.", options:["à","dans","de","par"], correct:0, rule:"« présenter quelque chose à quelqu'un » : présenter son projet à ses employés.", why:[null,"« dans » ne convient pas.","« de » non plus.","« par » non plus."] },
  { level:"A2", sentence:"Vous pouvez ___ ce fromage avec de la salade verte.", options:["couper","peser","sentir","servir"], correct:3, rule:"« servir » = présenter un plat : servir ce fromage avec de la salade.", why:["« couper » = trancher.","« peser » = mesurer le poids.","« sentir » = humer.",null] },
  { level:"B1", sentence:"Je suis assez inquiète pour notre déménagement mais mon mari pas du tout. Il est sûr que tout va bien se passer, il est très ___", options:["confiant.","curieux.","généreux.","ouvert"], correct:0, rule:"« confiant » = sûr que tout ira bien : il est confiant.", why:[null,"« curieux » sans rapport.","« généreux » non plus.","« ouvert » non plus."] },
  { level:"B1", sentence:"Je ne comprends comment Thibaud a fait : le résultat de son exercice de math est correct mais ___ n'est pas juste.", options:["sa déduction","sa réflexion","son observation","son raisonnement"], correct:3, rule:"« raisonnement » = enchaînement logique : le résultat est correct mais le raisonnement faux.", why:["« déduction » est plus restreint.","« réflexion » est plus vague.","« observation » sans rapport.",null] },
  { level:"B1", sentence:"Cette année, le directeur a souhaité mettre ___ de nouveaux horaires pour les salariés de son entreprise.", options:["en difficulté","en place","en question","en situation"], correct:1, rule:"« mettre en place » = instaurer : mettre en place de nouveaux horaires.", why:["« en difficulté » = compliquer.",null,"« en question » = remettre en cause.","« en situation » sans rapport."] },
  { level:"B1", sentence:"La limitation de vitesse est le meilleur ___ aux accidents de la route.", options:["médicament","remède","traitement","vaccin"], correct:1, rule:"« remède » = solution à un problème : le meilleur remède aux accidents (sens figuré).", why:["« médicament » est concret/médical.",null,"« traitement » est médical.","« vaccin » est médical."] },
  { level:"A2", sentence:"Pour créer une ambiance chaleureuse et agréable pour un dîner entre amis, posez des ___ sur la table et sur tous les meubles.", options:["bougies","cierges","flambeaux","torches"], correct:0, rule:"« bougies » créent une ambiance chaleureuse sur une table de dîner.", why:[null,"« cierges » sont religieux/grands.","« flambeaux » sont des torches.","« torches » sont pour l'extérieur."] },
  { level:"C1", sentence:"Lors de la dernière édition de la journée éco-citoyenne, on a vu ___ de nouvelles idées en matière de développement durable.", options:["prospérer","fleurir","fructifier","moissonner"], correct:1, rule:"« fleurir » au sens figuré = apparaître en abondance : voir fleurir de nouvelles idées.", why:["« prospérer » = se développer (économie).",null,"« fructifier » = donner des fruits/profits.","« moissonner » = récolter."] },
  { level:"C1", sentence:"Je vais aborder directement le point de ce rapport qui nous concerne tout particulièrement et je vous ferai donc ___ des détails.", options:["don","grâce","montre","part"], correct:1, rule:"« faire grâce de » = épargner, dispenser : je vous ferai grâce des détails.", why:["« don » → faire don = donner.",null,"« montre » → faire montre = montrer.","« part » → faire part = annoncer."] },
  { level:"A1", sentence:"Antoine et Christelle sont très sportifs ! Leur activité préférée c'est ___", options:["la lecture.","la télévision.","le piano.","le tennis."], correct:3, rule:"« le tennis » : activité sportive, cohérente avec « très sportifs ».", why:["« la lecture » n'est pas sportive.","« la télévision » non plus.","« le piano » non plus.",null] },
  { level:"B1", sentence:"Cette émission vous invite à ___ des produits de la cuisine française.", options:["ajouter","connaître","mélanger","prendre"], correct:1, rule:"« connaître des produits » = les découvrir/apprendre. Sens correct ici.", why:["« ajouter » ne convient pas.",null,"« mélanger » non plus.","« prendre » non plus."] },
  { level:"A1", sentence:"Au guichet de la piscine, Lucie ___ sa carte d'abonnement pour rentrer.", options:["montre","offre","range","vend"], correct:0, rule:"« montrer » : présenter sa carte au guichet pour entrer.", why:[null,"« offrir » = donner.","« ranger » = mettre en ordre.","« vendre » = céder contre argent."] },
  { level:"B1", sentence:"Il y a des grèves, j'ai peur que l'avion ___ en retard.", options:["est","était","sera","soit"], correct:3, rule:"Après « avoir peur que », on emploie le subjonctif : que l'avion soit.", why:["« est » est l'indicatif présent.","« était » l'imparfait.","« sera » le futur.",null] },
  { level:"B1", sentence:"Ces chaussures ont l'air confortable mais je préfère ___ en cuir noir, je les trouve vraiment magnifiques.", options:["celles","elles","les","lesquelles"], correct:0, rule:"« celles » = pronom démonstratif féminin pluriel remplaçant « chaussures ».", why:[null,"« elles » est un pronom sujet.","« les » est un article/COD.","« lesquelles » est un pronom relatif/interrogatif."] },
  { level:"B1", sentence:"Des spécialistes du monde animal réunis à Paris cette semaine pensent que plus de 15 000 ___ sont en danger et disparaîtront au cours des cinquante prochaines années.", options:["espèces","genres","sortes","types"], correct:0, rule:"« espèces » = catégories d'êtres vivants : 15 000 espèces en danger.", why:[null,"« genres » est une catégorie plus large/grammaticale.","« sortes » est vague.","« types » est vague."] },
  { level:"B1", sentence:"Ta mère a réagi comme cela parce qu'elle ne savait pas ce ___ s'était passé.", options:["dont","pourquoi","que","qui"], correct:3, rule:"« ce qui » : pronom relatif sujet (qui = sujet de « s'était passé »). « ce » est l'antécédent neutre.", why:["« dont » remplace un complément en « de ».","« pourquoi » demande une raison.","« que » serait COD, mais ici il faut un sujet.",null] },
  { level:"B2", sentence:"Tu me diras à quelle heure arrive ton train ___ que je vienne te chercher à la gare.", options:["à condition","afin","bien","de peur"], correct:1, rule:"« afin que » + subjonctif (vienne) exprime le but : pour que je vienne te chercher.", why:["« à condition » exprime une condition.",null,"« bien » ne forme pas de conjonction de but.","« de peur » exprime la crainte."] },
  { level:"C1", sentence:"Pendant son discours, le père de la mariée a exprimé toute sa joie : il était littéralement ___", options:["au point.","aux anges.","de marbre.","en nage."], correct:1, rule:"« être aux anges » = être au comble de la joie. Expression idiomatique.", why:["« au point » = prêt/réglé.",null,"« de marbre » = impassible (sens opposé).","« en nage » = en sueur."] },
  { level:"B2", sentence:"Le terreau fertile sur lequel cette famille a bâti ses affaires l'a rendue ___", options:["faste.","favorable.","luxueuse.","prospère."], correct:3, rule:"« prospère » = florissante, qui réussit : une famille rendue prospère par ses affaires.", why:["« faste » = somptueux (occasion).","« favorable » = propice.","« luxueuse » = riche en luxe.",null] },
  { level:"A2", sentence:"Bonjour Hugues, je suis absente aujourd'hui, dites aux clients de ___ demain matin. Merci.", options:["rappeler","rapporter","recommencer","répéter"], correct:0, rule:"« rappeler » = téléphoner à nouveau : dites aux clients de rappeler demain.", why:[null,"« rapporter » = ramener.","« recommencer » = refaire depuis le début.","« répéter » = redire."] },
  { level:"A2", sentence:"Il joue ___ la guitare tous les jours après les cours.", options:["à","dans","de","sur"], correct:2, rule:"« jouer de » s'emploie pour les instruments de musique : jouer de la guitare.", why:["« à » s'emploie pour les jeux/sports (jouer au foot).","« dans » ne convient pas.",null,"« sur » ne convient pas."] },
  { level:"A2", sentence:"Ce nouveau dictionnaire est très ___, tous les professeurs l'utilisent.", options:["complet","entier","occupé","plein"], correct:0, rule:"« complet » = qui contient tout : un dictionnaire complet.", why:[null,"« entier » = non divisé.","« occupé » = pris/affairé.","« plein » = rempli (matériel)."] },
  { level:"A2", sentence:"___ quelle formation vas-tu t'inscrire ?", options:["À","De","En","Par"], correct:0, rule:"« À quelle formation t'inscrire » : « s'inscrire à » se construit avec « à ».", why:[null,"« De » ne convient pas.","« En » non plus.","« Par » non plus."] },
  { level:"B2", sentence:"Proposez-moi une destination pour mes vacances, n'importe ___ me conviendra ! Mais je ne peux partir que la première semaine du mois prochain.", options:["comment","laquelle","quand","qui"], correct:1, rule:"« n'importe laquelle » = peu importe laquelle (destination, féminin). Reprend « destination ».", why:["« comment » = la manière.",null,"« quand » = le moment.","« qui » = la personne."] },
  { level:"B1", sentence:"Imane est un vrai modèle pour son frère. Comme elle a changé de chambre, il veut ___", options:["faire envie.","faire illusion.","faire pareil.","faire semblant."], correct:2, rule:"« faire pareil » = faire la même chose : il veut faire pareil (changer de chambre aussi).", why:["« faire envie » = susciter le désir.","« faire illusion » = tromper.",null,"« faire semblant » = feindre."] },
  { level:"B2", sentence:"___ qu'il était sur le point d'être diffusé ce soir à la télévision, ce reportage a été supprimé des programmes.", options:["Alors","En même temps","Pendant","Tandis"], correct:0, rule:"« Alors qu' » = au moment où / bien que : marque le contraste temporel ici.", why:[null,"« En même temps » ne se construit pas avec « que » ainsi.","« Pendant » a besoin de « que » mais le sens d'opposition appelle « alors ».","« Tandis » s'emploie aussi avec « que » mais « alors que » est plus naturel ici."] },
  { level:"B2", sentence:"Le prix Nobel de littérature sera ___ jeudi soir à une poétesse africaine.", options:["décerné","décrété","désigné","diffusé"], correct:0, rule:"« décerner un prix » = l'attribuer officiellement. Participe « décerné » au futur passif.", why:[null,"« décrété » = ordonné par décret.","« désigné » = nommé.","« diffusé » = répandu/émis."] },
  { level:"C1", sentence:"___ des habitants de Cordoue, ceux du Maroc étaient célèbres pour leur art de travailler le cuir.", options:["À l'instar","À l'affiche","À l'initiative","À l'origine"], correct:0, rule:"« À l'instar de » = à la manière de, comme : à l'instar des habitants de Cordoue.", why:[null,"« À l'affiche » = programmé (spectacle).","« À l'initiative » = à l'origine d'une action.","« À l'origine » = au départ."] },
  { level:"B2", sentence:"Dès son plus jeune âge, Georges Simenon avait ___ sa vie à sa passion, l'écriture.", options:["dédié","détourné","renoncé","résolu"], correct:0, rule:"« dédier sa vie à » = la consacrer entièrement : il avait dédié sa vie à l'écriture.", why:[null,"« détourné » = écarté.","« renoncé » se construit avec « à » mais sens opposé.","« résolu » = décidé/réglé."] },
  { level:"A1", sentence:"Laure adore son cadeau d'anniversaire, elle est très ___", options:["contente.","gentille.","jalouse.","triste."], correct:0, rule:"« contente » = satisfaite, heureuse : elle adore son cadeau, elle est contente.", why:[null,"« gentille » = aimable (trait de caractère).","« jalouse » = envieuse.","« triste » = malheureuse (opposé)."] },
  { level:"A1", sentence:"Ne mets pas ta valise ___ le lit, tu vas le salir !", options:["dans","derrière","entre","sur"], correct:3, rule:"« sur le lit » : « sur » indique la position au-dessus d'une surface.", why:["« dans » = à l'intérieur.","« derrière » = à l'arrière.","« entre » = au milieu de deux.",null] },
  { level:"A1", sentence:"Nous sommes heureux de vous ___ à la réunion du 22 janvier.", options:["appeler","écouter","inviter","présenter"], correct:2, rule:"« inviter quelqu'un à » : nous sommes heureux de vous inviter à la réunion.", why:["« appeler » = téléphoner/nommer.","« écouter » = entendre.",null,"« présenter » = montrer."] },
  { level:"A2", sentence:"À la sortie de l'autoroute, pensez à ___ pour éviter un accident.", options:["démarrer","ralentir","reculer","stationner"], correct:1, rule:"« ralentir » = réduire la vitesse : ralentir à la sortie d'autoroute pour éviter un accident.", why:["« démarrer » = se mettre en route.",null,"« reculer » = aller en arrière.","« stationner » = se garer."] },
  { level:"B2", sentence:"De toutes les villes que j'ai visitées, Lyon est celle ___ j'ai préférée.", options:["dont","où","que","qui"], correct:2, rule:"« que » : pronom relatif COD (Lyon est celle que j'ai préférée). Accord du participe avec « celle ».", why:["« dont » remplace un complément en « de ».","« où » indique le lieu.",null,"« qui » serait sujet."] },
  { level:"B2", sentence:"Pour accéder gratuitement à la bibliothèque, il faut demander une carte spéciale ___ sur présentation d'un justificatif de domicile.", options:["attestée","déchargée","délivrée","enregistrée"], correct:2, rule:"« délivrée » = remise officiellement : une carte délivrée sur présentation d'un justificatif.", why:["« attestée » = certifiée.","« déchargée » = libérée d'une charge.",null,"« enregistrée » = inscrite."] },
  { level:"B2", sentence:"On est tombés en panne sèche à 10 kilomètres d'une station-service. Plus ___ d'essence !", options:["un brin","un gramme","une goutte","une larme"], correct:2, rule:"« plus une goutte » = absolument plus du tout (de liquide). Expression de quantité nulle.", why:["« un brin » = un petit peu (de courage, d'herbe).","« un gramme » = unité de poids.",null,"« une larme » s'emploie au figuré pour une très petite quantité de boisson, mais « goutte » est l'expression usuelle pour l'essence."] },
  { level:"B2", sentence:"En raison des gelées tardives du printemps dernier, la production de raisin devrait chuter de 20% par rapport à celle de l'année dernière. ___ la qualité des fruits sera excellente.", options:["D'ailleurs,","En plus,","Par conséquent,","Toutefois,"], correct:3, rule:"« Toutefois » marque l'opposition : la production baisse, toutefois la qualité sera excellente.", why:["« D'ailleurs » ajoute un argument.","« En plus » ajoute.","« Par conséquent » exprime la conséquence.",null] },
  { level:"C1", sentence:"Au milieu du vingtième siècle, peu de gens parlaient d'énergie solaire, mais depuis, l'idée a fait son ___", options:["chemin.","marché.","profit.","temps."], correct:0, rule:"« faire son chemin » = progresser, se répandre (une idée). Expression idiomatique.", why:[null,"« marché » ne forme pas l'expression.","« profit » non plus.","« temps » non plus."] },
  { level:"B1", sentence:"Son exposé était tellement ___ qu'il a obtenu les félicitations du jury.", options:["convaincant","entraînant","inconsistant","pesant"], correct:0, rule:"« convaincant » = qui persuade : un exposé si convaincant qu'il a obtenu les félicitations.", why:[null,"« entraînant » = qui donne de l'entrain.","« inconsistant » = sans consistance (opposé).","« pesant » = lourd/ennuyeux."] },
  { level:"A1", sentence:"Maman, mes ___ de l'école vont jouer au basket cet après-midi. Je peux y aller avec eux ?", options:["copains","élèves","enfants","voisins"], correct:0, rule:"« copains » = camarades/amis : mes copains de l'école vont jouer.", why:[null,"« élèves » est neutre/scolaire, moins naturel ici.","« enfants » désigne sa progéniture.","« voisins » ne sont pas « de l'école »."] },
  { level:"A2", sentence:"Je suis un peu en retard et les invités arrivent à 20h à la maison, tu pourrais ___ la table pour le dîner, s'il te plaît ?", options:["apporter","faire","mettre","réserver"], correct:2, rule:"« mettre la table » = disposer les couverts. Collocation figée.", why:["« apporter » = porter vers.","« faire » ne se dit pas « faire la table ».",null,"« réserver » = retenir."] },
  { level:"A2", sentence:"Merci pour l'invitation ! Tu as cuisiné ___ que je préfère !", options:["l'assiette","la carte","la recette","l'alimentation"], correct:2, rule:"« la recette » = la préparation cuisinée : tu as cuisiné la recette que je préfère.", why:["« l'assiette » = le contenant.","« la carte » = le menu.",null,"« l'alimentation » = la nourriture en général."] },
  { level:"A2", sentence:"Nous allons passer les vacances d'été dans la région ___ nous étions l'année dernière. C'est vraiment magnifique !", options:["dont","où","que","qui"], correct:1, rule:"« où » : pronom relatif de lieu (la région où nous étions).", why:["« dont » remplace un complément en « de ».",null,"« que » serait COD.","« qui » serait sujet."] },
  { level:"A2", sentence:"En allant sur le forum du journal en ligne, vous pouvez participer à notre ___ sur la façon d'économiser l'énergie chez vous.", options:["conclusion","discussion","dispute","entretien"], correct:1, rule:"« discussion » = échange d'idées : participer à notre discussion sur l'énergie.", why:["« conclusion » = fin/résultat.",null,"« dispute » = querelle.","« entretien » = conversation formelle/maintenance."] },
  { level:"B1", sentence:"Trafic normal aujourd'hui. Toutefois, les ___ étant en grève, il n'y aura donc pas de vérification des billets dans les trains.", options:["chauffeurs","conducteurs","contrôleurs","guichetiers"], correct:2, rule:"« contrôleurs » = ceux qui vérifient les billets dans les trains.", why:["« chauffeurs » conduisent.","« conducteurs » conduisent le train.",null,"« guichetiers » vendent au guichet."] },
  { level:"B1", sentence:"Notre bibliothèque est devenue un lieu de vie où chacun peut trouver sa place et ___ aux projets tout au long de l'année.", options:["contribuer","convier","partager","réaliser"], correct:0, rule:"« contribuer à » = participer/apporter sa part : contribuer aux projets.", why:[null,"« convier » = inviter.","« partager » a besoin d'un COD.","« réaliser » = accomplir."] },
  { level:"C1", sentence:"Le secteur du numérique manque de candidats car il y a un problème ___ entre les besoins des entreprises et l'offre de formation.", options:["d'adéquation","d'éducation","d'exploitation","d'interaction"], correct:0, rule:"« un problème d'adéquation » = de correspondance/ajustement entre besoins et offre.", why:[null,"« d'éducation » sans rapport.","« d'exploitation » sans rapport.","« d'interaction » est proche mais « adéquation » exprime le décalage offre/besoin."] },
  { level:"C1", sentence:"Après avoir échoué plusieurs fois à l'examen final, le jeune homme s'est ___, avec grand regret, de ses études de sociologie.", options:["dédié","détourné","remis","rendu"], correct:1, rule:"« se détourner de » = abandonner, s'écarter de : il s'est détourné de ses études.", why:["« dédié » se construit avec « à ».",null,"« remis » ne convient pas.","« rendu » non plus."] },
  { level:"B2", sentence:"Samedi dernier, à Rouen, il a plu ___ que les quais ont été inondés.", options:["à tel point","d'autant moins","du plus loin","si ce n'est"], correct:0, rule:"« à tel point que » = tellement que : il a plu à tel point que les quais ont été inondés.", why:[null,"« d'autant moins » exprime une diminution proportionnelle.","« du plus loin » ne convient pas.","« si ce n'est » = sauf/excepté."] },
  { level:"A1", sentence:"Pour notre voyage ce week-end, je voudrais ___ une chambre d'hôtel.", options:["acheter","changer","louer","réserver"], correct:3, rule:"« réserver » = retenir à l'avance : réserver une chambre d'hôtel.", why:["« acheter » ne se dit pas d'une chambre d'hôtel.","« changer » = modifier.","« louer » est possible mais « réserver » est l'action pour un séjour court.",null] },
  { level:"A2", sentence:"La Bretagne est une région ___ pour ses spécialités au beurre.", options:["accueillie","apprise","connue","réservée"], correct:2, rule:"« connue pour » = réputée : une région connue pour ses spécialités.", why:["« accueillie » = reçue.","« apprise » = mémorisée.",null,"« réservée » = retenue/discrète."] },
  { level:"A2", sentence:"Votre vêtement n'est pas à la bonne taille ? Dans notre magasin, vous avez 30 jours pour ___ vos articles.", options:["commander","échanger","enlever","réserver"], correct:1, rule:"« échanger » = remplacer un article par un autre : 30 jours pour échanger vos articles.", why:["« commander » = passer commande.",null,"« enlever » = retirer.","« réserver » = retenir."] },
  { level:"A2", sentence:"Si vous voyez un feu dans cette forêt, quelle que soit la période de l'année, ___ vite les pompiers.", options:["alertez","composez","déclarez","rencontrez"], correct:0, rule:"« alerter » = avertir d'un danger : alertez vite les pompiers.", why:[null,"« composer » s'emploie pour un numéro (composez le 18).","« déclarer » = annoncer officiellement.","« rencontrer » = voir."] },
  { level:"A2", sentence:"Les collègues de Michel sont très ___ car ils l'attendent depuis une demi-heure pour leur réunion.", options:["égoïstes","énervés","jaloux","sérieux"], correct:1, rule:"« énervés » = agacés : ils attendent depuis une demi-heure, donc énervés.", why:["« égoïstes » = qui pensent à eux.",null,"« jaloux » = envieux.","« sérieux » = appliqués."] },
  { level:"B2", sentence:"Toute activité économique susceptible de ___ à l'environnement doit être interrompue dans le but de protéger les écosystèmes.", options:["céder","conduire","nuire","réagir"], correct:2, rule:"« nuire à » = causer du tort : une activité susceptible de nuire à l'environnement.", why:["« céder » = abandonner.","« conduire » = mener.",null,"« réagir » = répondre."] },
  { level:"C1", sentence:"___ l'âge et la condition physique, il est recommandé de pratiquer une activité sportive.", options:["Quel que soit","Quelle que soit","Quelles que soient","Quels que soient"], correct:3, rule:"« Quels que soient » s'accorde au masculin pluriel avec deux noms (l'âge ET la condition) dont un masculin.", why:["« Quel que soit » est singulier.","« Quelle que soit » est féminin singulier.","« Quelles que soient » serait si les deux noms étaient féminins.",null] },
  { level:"B2", sentence:"Lors des dernières élections, le candidat de l'opposition a proposé ___ les jeunes de sa commune dans l'organisation des événements culturels.", options:["d'adresser","d'appliquer","d'étendre","d'impliquer"], correct:3, rule:"« impliquer quelqu'un dans » = le faire participer : impliquer les jeunes dans l'organisation.", why:["« adresser » se construit autrement.","« appliquer » ne convient pas.","« étendre » = agrandir.",null] },
  { level:"B2", sentence:"Il pleut des cordes ! Pense à enlever tes chaussures avant d'entrer dès que tu ___ arrivée à la maison. Bises. Maman", options:["es","étais","serais","seras"], correct:3, rule:"« dès que tu seras arrivée » : après « dès que » avec un futur, on emploie le futur (ici futur simple « seras »).", why:["« es » est le présent.","« étais » l'imparfait.","« serais » le conditionnel.",null] },
  { level:"C1", sentence:"Patrice a fait des pieds et des mains pour faire embaucher Carmen dans son entreprise. Il a vraiment fait tout ce qui était en son ___", options:["droit.","lieu.","nom.","pouvoir."], correct:3, rule:"« faire tout ce qui était en son pouvoir » = faire tout son possible. Expression figée.", why:["« droit » ne forme pas l'expression.","« lieu » non plus.","« nom » non plus.",null] },
];
